package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	ID      int
	Content string
}

var comments = []Comment{
	{ID: 1, Content: "This is a <b>bold</b> comment."},
	{ID: 2, Content: "Here's an <i>italic</i> one!"},
	// Add more comments as needed
}

func main() {
	http.HandleFunc("/comments", func(w http.ResponseWriter, r *http.Request) {
		tmpl := template.Must(template.New("comments").Parse(`
			<!DOCTYPE html>
			<html lang="en">
			<head>
				<meta charset="UTF-8">
				<title>Comments</title>
			</head>
			<body>
				<h1>User Comments</h1>
				{{range .}}
					<div>
						<p>{{.Content | html}}</p>
					</div>
				{{end}}
			</body>
			</html>
		`))
		tmpl.Execute(w, comments)
	})

	http.ListenAndServe(":8080", nil)
}